mapper.select:
select array_to_json(array_agg(row_to_json(t)))
from (
select p2.text_id, p2.property_value

  , p1._meta

from core.text_property_added as p2

  join core.text_added as p1 on p2.text_id = p1.id


  join core.text_property_added as ${singleParamHelper.table} on p2.text_id = ${singleParamHelper.table}.text_id



    join core.text_property_added as ${multiParamHelper.table} on p2.text_id = ${multiParamHelper.table}.text_id



  join core.text_property_added as ${otherLangHelper.table} on p2.text_id = ${otherLangHelper.table}.text_id

where p2.property_name = 'title'

  and ${singleParamHelper.table}.property_name = #{singleParamHelper.parameter}
  and ${singleParamHelper.table}.property_value = #{singleParamHelper.value}



    and ${multiParamHelper.table}.property_name = #{multiParamHelper.parameter}
    and ${multiParamHelper.table}.property_value in

      #{multiParam}





  and ${otherLangHelper.table}.property_name = #{otherLangHelper.parameter}
  and ${otherLangHelper.table}.property_value ilike #{likeValue}

) t

mapper.update:
update core.text_added
set content = #{content}
where id = #{textId}
